insert into public.airports (id, name, icao, iata, faa_lid, city_slug, state_slug, description) values
  ('kffz', 'Falcon Field Airport', 'KFFZ', 'MSC', 'FFZ', 'mesa', 'arizona', 'Falcon Field Airport (KFFZ) in Mesa, Arizona is one of the busiest general aviation airports in the United States. Originally built as a World War II training base for British RAF pilots, the airport today serves a thriving community of flight schools, charter operators, and private pilots. Its uncongested airspace, 300+ days of sunshine per year, and proximity to the Phoenix metro make it an ideal location for year-round flight training from first solo through advanced ratings.'),
  ('kdvt', 'Phoenix Deer Valley Airport', 'KDVT', null, 'DVT', 'phoenix', 'arizona', 'Phoenix Deer Valley Airport (KDVT) is one of the nation''s busiest single-runway general aviation airports, handling hundreds of operations daily in the northwest Phoenix metro. The airport''s Class D airspace and pattern-intensive environment give student pilots exceptional radio communication and traffic-awareness experience early in their training. Excellent VFR weather, a modern terminal, and multiple flight school tenants make KDVT a top choice for Private Pilot through CFI training.'),
  ('kphx', 'Phoenix Sky Harbor International', 'KPHX', 'PHX', 'PHX', 'phoenix', 'arizona', 'Phoenix Sky Harbor International Airport (KPHX) is the primary commercial service airport for the greater Phoenix metropolitan area and one of the busiest airports in the American Southwest. As a Class B airport, it serves as an important navigational reference and airspace boundary for student pilots training at nearby GA fields. Some advanced and instrument-rated training programs conduct Class B transition flights out of KPHX to give students real-world experience in complex, high-traffic airspace.'),
  ('kchd', 'Chandler Municipal Airport', 'KCHD', null, 'CHD', 'chandler', 'arizona', 'Chandler Municipal Airport (KCHD) is a general aviation reliever airport in the southeast Phoenix metro. With minimal commercial traffic and a relaxed pattern environment, KCHD is well-suited for primary flight training. The airport sits within easy flying distance of several practice areas in the Sonoran Desert and benefits from the same 300+ days of VFR weather that makes the entire Phoenix metro a pilot-training hub.'),
  ('ktus', 'Tucson International Airport', 'KTUS', 'TUS', 'TUS', 'tucson', 'arizona', 'Tucson International Airport (KTUS) serves both commercial airline traffic and a robust general aviation community in southern Arizona. Situated at roughly 2,600 feet MSL with consistent desert VFR conditions, KTUS is home to several flight training programs that leverage the region''s clear skies and diverse terrain — from desert flatlands to mountain ridges — for well-rounded pilot development. Instrument students benefit from the full suite of ILS, RNAV, and VOR approaches serving the airport.'),
  ('kcps', 'St. Louis Downtown Airport', 'KCPS', 'CPS', 'CPS', 'belleville', 'illinois', 'St. Louis Downtown Airport (KCPS), located in Belleville, Illinois, is a general aviation reliever airport serving the greater St. Louis metro area. Despite its Illinois address, KCPS functions as a practical training hub for pilots from both sides of the Mississippi River. Its relatively quiet pattern and proximity to St. Louis Lambert''s Class B airspace give student pilots valuable exposure to complex airspace transitions while keeping training costs manageable at a non-commercial field.'),
  ('kstl', 'St. Louis Lambert International', 'KSTL', 'STL', 'STL', 'st-louis', 'missouri', 'St. Louis Lambert International Airport (KSTL) is Missouri''s largest and busiest airport, anchoring the St. Louis metro''s aviation infrastructure. As a Class B facility with multiple parallel runways and a full ILS/RNAV approach suite, KSTL is the benchmark airspace environment for instrument-rated pilots training in the region. Flight schools operating here give students unparalleled exposure to real-world ATC communication and commercial traffic procedures in a major hub environment.'),
  ('kmkc', 'Charles B. Wheeler Downtown Airport', 'KMKC', 'MKC', 'MKC', 'kansas-city', 'missouri', 'Charles B. Wheeler Downtown Airport (KMKC) sits along the Missouri River just north of downtown Kansas City, offering a uniquely urban backdrop for general aviation training. The airport features Class D airspace and sits comfortably clear of Kansas City International''s Class B, making it an ideal base for primary training with convenient access to practice areas and cross-country routes across the Great Plains. Its downtown location means easy access for Kansas City-area students.'),
  ('kojc', 'Johnson County Executive Airport', 'KOJC', 'OJC', 'OJC', 'overland-park', 'kansas', 'Johnson County Executive Airport (KOJC) in Overland Park, Kansas is a modern GA reliever airport serving the prosperous Kansas side of the Kansas City metro. With a well-maintained runway, instrument approaches, and a growing roster of flight school tenants, KOJC is the go-to training airport for students in Johnson County and the surrounding suburbs. Its Class D airspace and active pattern traffic give trainees solid radio discipline and situational awareness from their earliest lessons.'),
  ('kixd', 'New Century Aircenter', 'KIXD', null, 'IXD', 'overland-park', 'kansas', 'New Century Aircenter (KIXD) is a general aviation airport located southwest of the Kansas City metro near Gardner, Kansas. Originally built as Olathe Naval Air Station, the airport retains wide runways and excellent facilities suited to both primary training and complex/high-performance operations. Its non-towered environment and multiple runways offer student pilots flexibility in pattern work, while the relatively light traffic density provides a confidence-building setting for solo and cross-country flights.'),
  ('kfxe', 'Fort Lauderdale Executive Airport', 'KFXE', 'FXE', 'FXE', 'fort-lauderdale', 'florida', 'Fort Lauderdale Executive Airport (KFXE) is one of the premier general aviation airports in South Florida, handling a mix of private jets, charter turboprops, and flight school traffic in Broward County. The airport''s Class D airspace, year-round VMC weather, and proximity to both Miami''s Class B and the Atlantic coast make it an outstanding environment for building diverse pilot experience. Multiple FAA-certificated flight schools call KFXE home, offering training from PPL through ATP in one of the country''s most active GA markets.'),
  ('kopf', 'Miami-Opa Locka Executive Airport', 'KOPF', 'OPF', 'OPF', 'miami', 'florida', 'Miami-Opa Locka Executive Airport (KOPF) is a busy general aviation reliever airport serving the northern Miami-Dade area. Situated just outside Miami''s Class B airspace, KOPF gives student pilots immediate access to one of the nation''s most complex airspace environments while training in a more manageable tower-controlled setting. Year-round tropical VFR conditions and a diverse surrounding landscape — coast, Everglades, and urban corridor — make for a rich and varied training experience.'),
  ('kpmp', 'Pompano Beach Airpark', 'KPMP', 'PMP', 'PMP', 'pembroke-pines', 'florida', 'Pompano Beach Airpark (KPMP) is a general aviation airport in Broward County, Florida, ideally positioned between Fort Lauderdale and Boca Raton. With a non-towered environment, a single active runway, and consistent South Florida VFR weather, KPMP is a popular base for primary and multi-engine flight training. Student pilots here quickly become comfortable with self-announce procedures and uncontrolled pattern operations — skills that translate directly to real-world cross-country flying.'),
  ('kmyf', 'Montgomery-Gibbs Executive Airport', 'KMYF', 'MYF', 'MYF', 'san-diego', 'california', 'Montgomery-Gibbs Executive Airport (KMYF) is San Diego''s busiest general aviation airport, located in the Mission Hills area just eight miles northeast of downtown. Its Class D airspace, coastal proximity, and mild year-round weather create an exceptional training environment where students fly over Pacific beaches, mountains, and desert terrain within a single lesson. KMYF hosts numerous flight training programs and benefits from San Diego''s remarkably consistent VFR conditions, averaging fewer IFR days per year than almost any major metro in the country.'),
  ('kcrq', 'McClellan-Palomar Airport', 'KCRQ', 'CLD', 'CLD', 'san-diego', 'california', 'McClellan-Palomar Airport (KCRQ) in Carlsbad, California serves the north San Diego County coast and is one of Southern California''s most active general aviation airports. The airport''s tower-controlled environment, ILS approach, and proximity to both LAX and SAN Class B airspace give students valuable experience navigating complex SoCal airspace. Marine-layer mornings followed by clear afternoons mean IFR students get genuine IMC exposure while VFR students enjoy some of the best cross-country flying conditions in the western United States.'),
  ('klax', 'Los Angeles International Airport', 'KLAX', 'LAX', 'LAX', 'los-angeles', 'california', 'Los Angeles International Airport (KLAX) is one of the world''s busiest airports and the primary commercial aviation gateway to Southern California. As a Class B airport with multiple parallel runways and extraordinarily dense ATC traffic, KLAX itself is not a typical flight training base — but it forms the centerpiece of the LA Basin''s complex airspace that every SoCal instrument student must learn to navigate. Advanced and instrument-rated training programs regularly conduct Class B operations and approaches into KLAX to give students authentic high-workload flight experience.'),
  ('kbna', 'Nashville International Airport', 'KBNA', 'BNA', 'BNA', 'nashville', 'tennessee', 'Nashville International Airport (KBNA) is Tennessee''s busiest airport, serving both commercial airline traffic and a growing general aviation community in the heart of Middle Tennessee. The airport''s Class C airspace, multiple instrument approaches, and diverse surrounding terrain — rolling hills, river valleys, and open farmland — make it an excellent environment for instrument and commercial training. Flight schools operating at KBNA give students real-world exposure to ATC procedures at a major regional hub without the complexity of a full Class B facility.'),
  ('kcha', 'Chattanooga Metropolitan Airport', 'KCHA', 'CHA', 'CHA', 'chattanooga', 'tennessee', 'Chattanooga Metropolitan Airport (KCHA) serves the greater Chattanooga area in the scenic Tennessee River valley, flanked by Lookout Mountain and the ridges of the southern Appalachians. The airport''s Class C airspace and mix of commercial and GA traffic give student pilots meaningful ATC interaction in a less overwhelming environment than a major hub. The surrounding mountain terrain provides outstanding cross-country and instrument training routes, and the relatively mild four-season climate allows for solid year-round training schedules.')
insert into public.programs (id, slug, name, short_name, description, faa_part, minimum_hours, certificate, prerequisites, typical_duration, sort_order) values
  ('private-pilot', 'private-pilot', 'Private Pilot Certificate', 'Private Pilot', 'The Private Pilot Certificate (PPL) is the entry-level certificate that allows you to act as pilot in command of an aircraft. Under FAR Part 61, you need a minimum of 40 flight hours; FAA-certificated Part 141 schools can complete training in as few as 35 hours. Training covers basic aircraft control, navigation, cross-country planning, night flying, and emergency procedures. Upon completion you''ll pass both a written knowledge exam and a practical checkride with an FAA-designated pilot examiner.', 'both', 40, 'FAA Private Pilot Certificate', '[]'::jsonb, '6–12 months', 1),
  ('instrument-rating', 'instrument-rating', 'Instrument Rating', 'Instrument Rating', 'The Instrument Rating (IR) allows you to fly in instrument meteorological conditions (IMC) — clouds, fog, and low visibility — using only cockpit instruments. Requirements under Part 61 include 50 hours of cross-country PIC time and 40 hours of actual or simulated instrument flight. The rating dramatically increases both the utility and safety of your certificate by enabling legal flight in challenging weather and into airports served by ILS and RNAV approaches.', 'both', 40, 'FAA Instrument Rating', '["private-pilot"]'::jsonb, '3–6 months', 3),
  ('commercial-pilot', 'commercial-pilot', 'Commercial Pilot Certificate', 'Commercial Pilot', 'The Commercial Pilot Certificate (CPL) authorizes you to be compensated for flying. Under Part 61, the minimums are 250 total flight hours including specific cross-country, instrument, and complex aircraft time. A commercial certificate is a prerequisite for most aviation careers — flight instruction, charter, cargo, and airline employment all require it at minimum as a stepping stone.', 'both', 250, 'FAA Commercial Pilot Certificate', '["private-pilot","instrument-rating"]'::jsonb, '12–24 months', 4),
  ('cfi', 'cfi', 'Certified Flight Instructor', 'CFI', 'The Certified Flight Instructor (CFI) certificate is the primary pathway for new commercial pilots to build flight hours. As a CFI, you are authorized to provide flight instruction and sign off student logbooks. Most regional airline-bound pilots log the bulk of their 1,500 ATP hours in the right seat of a trainer. The CFI practical test is considered one of the most demanding in aviation, covering deep aeronautical knowledge and teaching ability.', 'both', null, 'FAA Flight Instructor Certificate', '["commercial-pilot"]'::jsonb, '2–4 months', 5),
  ('cfii', 'cfii', 'Certified Flight Instructor – Instrument', 'CFII', 'The CFII add-on authorizes flight instructors to provide instrument flight instruction and conduct instrument proficiency checks. Requires an active CFI certificate plus an Instrument Rating. Many flight schools prefer instructors who hold both CFI and CFII ratings to handle the full range of their student curriculum.', 'both', null, 'FAA Flight Instructor Certificate – Instrument', '["cfi","instrument-rating"]'::jsonb, '1–2 months', 6),
  ('mei', 'mei', 'Multi-Engine Instructor', 'MEI', 'The Multi-Engine Instructor (MEI) rating is an add-on to the CFI certificate that authorizes providing flight instruction in multi-engine aircraft. Candidates must already hold a CFI certificate and a multi-engine rating. Training focuses on teaching engine-out procedures, asymmetric thrust management, and the systems knowledge unique to light twins. The MEI is a valuable credential for instructors at schools with multi-engine training programs and is a common step on the path toward turbine and airline employment.', 'both', null, 'Multi-Engine Instructor Rating (added to CFI certificate)', '["cfi","multi-engine"]'::jsonb, '1–2 weeks', 6.5),
  ('multi-engine', 'multi-engine', 'Multi-Engine Rating', 'Multi-Engine', 'The Multi-Engine Rating (MEL) is an add-on rating that authorizes operation of aircraft with more than one engine. It does not require a minimum number of flight hours — practical performance standards are the measure. Training focuses on asymmetric thrust management, engine-out procedures, systems knowledge, and the V-speed profiles unique to multi-engine aircraft. Most commercial and airline training tracks include a multi-engine rating.', 'both', null, 'Multi-Engine Rating (added to existing certificate)', '["private-pilot"]'::jsonb, '1–3 weeks', 7),
  ('atp', 'atp', 'Airline Transport Pilot Certificate', 'ATP', 'The Airline Transport Pilot (ATP) certificate is the highest level of FAA pilot certification and is required to serve as captain (PIC) of a Part 121 airliner. Under current FAA regulations, most candidates need 1,500 total flight hours, though military-trained pilots qualify at 750 hours and Part 141 graduates qualify at 1,000 hours. ATP candidates must hold a commercial certificate and instrument rating, pass the ATP written exam, and complete the ATP Certification Training Program (ATP CTP) before the checkride.', 'both', 1500, 'FAA Airline Transport Pilot Certificate', '["commercial-pilot","instrument-rating"]'::jsonb, 'Depends on total flight hours accumulated', 8),
  ('sport-pilot', 'sport-pilot', 'Sport Pilot Certificate', 'Sport Pilot', 'The Sport Pilot Certificate allows pilots to fly Light Sport Aircraft (LSA) — aircraft limited to a max gross weight of 1,320 lbs and two seats. Training minimums are 20 hours, and the certificate requires only a valid U.S. driver''s license as a medical requirement, making it accessible to many applicants who cannot obtain a standard FAA medical certificate. Sport pilot is an efficient path for recreational flying without the full PPL commitment.', 'both', 20, 'FAA Sport Pilot Certificate', '[]'::jsonb, '3–6 months', 2),
  ('discovery-flight', 'discovery-flight', 'Discovery Flight', 'Discovery Flight', 'A discovery flight is an introductory lesson designed for people curious about learning to fly. Typically 30–60 minutes, you''ll take the controls under the supervision of a CFI and experience the basics of aircraft control firsthand. Discovery flights are offered by most flight schools, often at a discounted introductory rate, and count as your first logbook entry if you later pursue a certificate.', null, null, null, '[]'::jsonb, '30–60 minutes', 9),
  ('ground-school', 'ground-school', 'Ground School', 'Ground School', 'Ground school covers the academic knowledge required to pass FAA written knowledge exams. Topics include aerodynamics, aircraft systems, weather, navigation, FARs and AIM, and airspace. Ground school may be delivered in-person at a flight school, online, or as part of an accelerated weekend course. Many flight schools recommend completing ground school concurrently with or before beginning flight training for maximum efficiency.', null, null, null, '[]'::jsonb, '4–12 weeks', 10),
  ('seaplane-rating', 'seaplane-rating', 'Seaplane Rating', 'Seaplane Rating', 'The Seaplane (Single-Engine Sea, SES) rating is an add-on to your existing certificate that authorizes flight in floatplanes and flying boats. Training covers water operations, docking, step taxi, glassy water landings, and takeoff/landing technique unique to amphibious and floatplane aircraft. The rating has no hour minimum and can be completed in as few as 5–10 hours at a seaplane base.', null, null, 'Seaplane Rating (added to existing certificate)', '["private-pilot"]'::jsonb, '2–5 days', 11),
  ('tailwheel', 'tailwheel', 'Tailwheel Endorsement', 'Tailwheel', 'The tailwheel (conventional landing gear) endorsement authorizes flight in aircraft where the third wheel is at the tail rather than the nose. Tailwheel aircraft require more precise ground handling technique due to their tendency toward ground loops. The endorsement requires demonstration of normal and crosswind takeoffs and landings, and wheel landings to the satisfaction of a CFI. No minimum hours are required.', null, null, 'Tailwheel Endorsement (logbook entry)', '["private-pilot"]'::jsonb, '1–3 days', 12),
  ('high-performance', 'high-performance', 'High Performance Endorsement', 'High Performance', 'The high-performance endorsement is required before acting as PIC of any aircraft with an engine rated at more than 200 horsepower. Training focuses on the additional systems, speeds, and performance considerations of more powerful aircraft. Common aircraft requiring this endorsement include the Cessna 182 Skylane and Beechcraft Bonanza.', null, null, 'High Performance Endorsement (logbook entry)', '["private-pilot"]'::jsonb, '1–2 days', 13),
  ('complex-endorsement', 'complex-endorsement', 'Complex Aircraft Endorsement', 'Complex', 'The complex aircraft endorsement is required before acting as PIC of any aircraft with retractable landing gear, flaps, AND a controllable-pitch propeller. It is required for Commercial Pilot training (FAR 61.129) unless using an Advanced Avionics Aircraft. Training covers retractable gear procedures, constant-speed propeller operation, emergency extension procedures, and appropriate V-speeds.', null, null, 'Complex Aircraft Endorsement (logbook entry)', '["private-pilot"]'::jsonb, '1–2 days', 14)
insert into public.trainer_aircraft (id, slug, make, model, display_name, category, description, common_use, engine_count, typical_cruise, sort_order) values
  ('cessna-152', 'cessna-152', 'Cessna', '152', 'Cessna 152', 'single-engine', 'The Cessna 152 is a two-seat, single-engine trainer that served as the backbone of American flight training from the late 1970s through the 1980s and remains widely used today. With a 110-horsepower Lycoming O-235 engine and docile handling characteristics, the 152 is ideal for primary training. Its lower operating cost compared to the Cessna 172 makes it a popular choice for solo practice and early dual instruction, particularly at schools focused on cost-efficient PPL training.', '["private-pilot","sport-pilot","discovery-flight"]'::jsonb, 1, '~107 knots', 2),
  ('cessna-172-skyhawk', 'cessna-172-skyhawk', 'Cessna', '172 Skyhawk', 'Cessna 172 Skyhawk', 'single-engine', 'The Cessna 172 Skyhawk is the most produced and most widely flown aircraft in history, with over 44,000 built since 1956. Its high-wing design provides exceptional visibility, its stable flight characteristics build pilot confidence, and its four-seat capacity allows for instructors and passengers. The 172 is used across virtually every flight school in the United States for Private Pilot through Instrument Rating training, making it the universal benchmark for general aviation trainers.', '["private-pilot","instrument-rating","commercial-pilot","cfi","cfii","discovery-flight"]'::jsonb, 1, '~122 knots', 1),
  ('cessna-182-skylane', 'cessna-182-skylane', 'Cessna', '182 Skylane', 'Cessna 182 Skylane', 'single-engine', 'The Cessna 182 Skylane is a four-seat, high-wing aircraft with a 230-horsepower fuel-injected Continental IO-470 or IO-540 engine. As a high-performance aircraft (>200 HP), it requires a separate FAA endorsement before acting as PIC. The Skylane''s greater useful load, higher cruise speed, and constant-speed propeller make it a natural progression aircraft for students transitioning from the Cessna 172 to more complex and cross-country-capable platforms.', '["commercial-pilot","instrument-rating","high-performance","complex-endorsement"]'::jsonb, 1, '~145 knots', 3),
  ('piper-pa28-cherokee', 'piper-pa28-cherokee', 'Piper', 'PA-28 Cherokee / Warrior / Archer', 'Piper PA-28 Cherokee', 'single-engine', 'The Piper PA-28 Cherokee (and its variants: Warrior, Archer, Arrow) is a low-wing, four-seat trainer that has competed with the Cessna 172 as one of the most popular primary trainers in American aviation. The low-wing configuration provides a different visual perspective for traffic avoidance and gives student pilots valuable experience in a platform similar to the majority of the world''s airline fleet. Cherokee variants range from 140 to 180 horsepower, offering a progression path within the same aircraft family.', '["private-pilot","instrument-rating","commercial-pilot","cfi","discovery-flight"]'::jsonb, 1, '~116 knots', 4),
  ('piper-pa44-seminole', 'piper-pa44-seminole', 'Piper', 'PA-44 Seminole', 'Piper PA-44 Seminole', 'multi-engine', 'The Piper PA-44 Seminole is the industry''s most common multi-engine trainer, used by flight schools across the country to teach multi-engine ratings and provide commercial students with multi-engine PIC time. Its counter-rotating propeller system means neither engine is a "critical engine" during engine-out scenarios, and its light-twin handling characteristics provide a logical step up from single-engine trainers for airline-track students.', '["multi-engine","commercial-pilot","atp","cfi"]'::jsonb, 2, '~163 knots', 9),
  ('beechcraft-duchess', 'beechcraft-duchess', 'Beechcraft', 'Duchess 76', 'Beechcraft Duchess', 'multi-engine', 'The Beechcraft Duchess (Model 76) is a four-seat, twin-engine trainer produced from 1978 to 1982 and commonly used at flight schools as an alternative to the Piper Seminole for multi-engine ratings. Like the Seminole, the Duchess features counter-rotating propellers and relatively benign handling characteristics well-suited to training. Its T-tail configuration and retractable landing gear also fulfill the requirements for the complex aircraft endorsement.', '["multi-engine","commercial-pilot","complex-endorsement"]'::jsonb, 2, '~155 knots', 10),
  ('beechcraft-baron-58', 'beechcraft-baron-58', 'Beechcraft', 'Baron 58', 'Beechcraft Baron 58', 'multi-engine', 'The Beechcraft Baron 58 is a six-seat, twin-engine aircraft powered by two Continental IO-520 or IO-550 engines producing 300 horsepower each. It represents the upper end of light-twin training, used at flight schools offering multi-engine commercial training and at ATP prep programs where students need multi-engine PIC time in a more capable platform. The Baron''s higher performance and systems complexity provide excellent preparation for turboprop and jet type ratings.', '["multi-engine","commercial-pilot","atp"]'::jsonb, 2, '~200 knots', 11),
  ('diamond-da20', 'diamond-da20', 'Diamond', 'DA20', 'Diamond DA20', 'single-engine', 'The Diamond DA20 is a two-seat composite trainer manufactured by Diamond Aircraft Industries. Its T-tail, low-wing design and carbon fiber construction make it distinctive among primary trainers, and its aerobatic capabilities (certified in the utility category) allow some schools to offer basic aerobatics training. The DA20''s modern design and excellent visibility from its canopy make it a popular choice for schools seeking an alternative to traditional Cessna/Piper designs for PPL training.', '["private-pilot","sport-pilot","discovery-flight"]'::jsonb, 1, '~108 knots', 5),
  ('diamond-da40', 'diamond-da40', 'Diamond', 'DA40 Diamond Star', 'Diamond DA40', 'single-engine', 'The Diamond DA40 Diamond Star is a four-seat, composite single-engine aircraft available with both piston and turbine powerplants. Its Garmin G1000 glass cockpit avionics suite is standard equipment on newer models, making it an excellent platform for building glass-cockpit proficiency alongside Private Pilot and Instrument Rating training. The DA40''s efficient diesel engine option provides reduced operating costs relative to comparable Cessna/Piper platforms.', '["private-pilot","instrument-rating","commercial-pilot"]'::jsonb, 1, '~147 knots', 6),
  ('diamond-da42', 'diamond-da42', 'Diamond', 'DA42 Twin Star', 'Diamond DA42', 'multi-engine', 'The Diamond DA42 Twin Star is a four-seat, twin-engine diesel aircraft widely used in professional and accelerated flight training programs. Equipped with the Garmin G1000 glass cockpit, it bridges the gap between traditional light-twin training and modern airline-type systems. The DA42 is approved under Part 135 charter operations and is used by some ATP accelerated training programs as a multi-engine turbine-simulation platform.', '["multi-engine","instrument-rating","commercial-pilot","atp"]'::jsonb, 2, '~178 knots', 12),
  ('cirrus-sr20', 'cirrus-sr20', 'Cirrus', 'SR20', 'Cirrus SR20', 'single-engine', 'The Cirrus SR20 is a four-seat composite aircraft with the Cirrus Airframe Parachute System (CAPS) — a whole-aircraft ballistic parachute deployable in emergencies. Its Garmin Perspective glass cockpit, side-stick controls, and overall modern design make it one of the most technologically advanced piston trainers available. Flight schools using the SR20 typically position it for advanced or accelerated training tracks where glass-cockpit proficiency and systems complexity are prioritized.', '["private-pilot","instrument-rating","commercial-pilot"]'::jsonb, 1, '~155 knots', 7),
  ('cirrus-sr22', 'cirrus-sr22', 'Cirrus', 'SR22', 'Cirrus SR22', 'single-engine', 'The Cirrus SR22 is the best-selling piston aircraft in the world for over a decade, and a premium platform for high-performance commercial training. With a 310-horsepower Continental IO-550-N engine, the SR22 cruises at over 185 knots and is equipped with TKS ice protection on some models. Like the SR20, it features CAPS and the Garmin Perspective avionics suite. Many integrated commercial training programs use the SR22 as their advanced single-engine platform for commercial and instrument rating training.', '["commercial-pilot","instrument-rating","high-performance","atp"]'::jsonb, 1, '~185 knots', 8),
  ('robinson-r22', 'robinson-r22', 'Robinson', 'R22 Beta II', 'Robinson R-22', 'helicopter', 'The Robinson R-22 Beta II is the world''s most widely used helicopter trainer, providing the foundation for helicopter Private Pilot, Commercial, and CFI training. Its two-seat, piston-powered design offers low operating costs that make helicopter training accessible to students pursuing rotor-wing certificates. The R-22''s light controls require precise technique and make it an excellent instrument for developing the coordination and scan patterns essential to helicopter flight.', '["private-pilot","commercial-pilot","cfi"]'::jsonb, 1, '~96 knots', 13),
  ('robinson-r44', 'robinson-r44', 'Robinson', 'R44 Raven', 'Robinson R-44', 'helicopter', 'The Robinson R-44 Raven is a four-seat helicopter widely used for advanced training, instrument currency, and introductory flights. Many helicopter schools progress students from the R-22 to the R-44 for their commercial pilot certificate due to its greater useful load and passenger-carrying capability. It is also used for instrument training when equipped with appropriate avionics, providing helicopter students the opportunity to earn an instrument rating in a cost-effective piston platform.', '["commercial-pilot","instrument-rating","cfi","discovery-flight"]'::jsonb, 1, '~110 knots', 14),
  ('vans-rv-12', 'vans-rv-12', 'Van''s Aircraft', 'RV-12', 'Van''s RV-12', 'sport', 'The Van''s RV-12 is a two-seat, low-wing Light Sport Aircraft (LSA) that is typically built from a kit and flown as a sport aircraft. Several flight schools operate factory-built versions of the RV-12 for Sport Pilot and primary training, where its responsive handling, modern design, and low operating cost distinguish it from traditional Cessna 150/152 trainers. The RV-12''s cruise speed of 110+ knots and fuel efficiency make it practical for cross-country training in the sport pilot category.', '["sport-pilot","private-pilot","discovery-flight"]'::jsonb, 1, '~110 knots', 15)
insert into public.flight_schools (id, name, slug, description, primary_airport_code, city_slug, state_slug, organization_id, rating, review_count, website, phone, featured, faa_part, contacts, estimated_planes, estimated_instructors) values
  ('arizona-pilot-academy-mesa', 'Arizona Pilot Academy', 'arizona-pilot-academy', 'Arizona Pilot Academy offers comprehensive flight training at Falcon Field Airport in Mesa. With a modern fleet and experienced instructors, we guide students from first flight through ATP certifications.', 'KFFZ', 'mesa', 'arizona', 'arizona-pilot-academy', 4.8, 142, 'https://example.com/arizona-pilot-academy', '(480) 555-0101', true, 'both', '[{"name":"Robert Hale","title":"Owner / Chief Pilot","phone":"(480) 555-0101","email":"rhale@example.com"},{"name":"Maria Santos","title":"Director of Training","phone":"(480) 555-0103","email":"msantos@example.com"},{"name":"Kevin Park","title":"Front Desk / Scheduling","phone":"(480) 555-0104","email":"kpark@example.com"}]'::jsonb, '10-20', '10-20'),
  ('arizona-pilot-academy-phoenix', 'Arizona Pilot Academy – Deer Valley', 'arizona-pilot-academy-deer-valley', 'Arizona Pilot Academy''s Deer Valley location at Phoenix Deer Valley Airport brings the same experienced instructors and modern fleet to the northwest Phoenix metro.', 'KDVT', 'phoenix', 'arizona', 'arizona-pilot-academy', 4.7, 58, 'https://example.com/arizona-pilot-academy', '(602) 555-0102', false, 'both', '[{"name":"Dana Cole","title":"Location Manager / CFI","phone":"(602) 555-0102","email":"dcole@example.com"},{"name":"Tina Ruiz","title":"Front Desk / Scheduling","phone":"(602) 555-0105","email":"truiz@example.com"}]'::jsonb, '6-9', '6-9'),
  ('midwest-flight-training', 'Midwest Flight Training', 'midwest-flight-training', 'Serving the St. Louis metro from St. Louis Downtown Airport in Belleville, IL, Midwest Flight Training provides quality instruction at competitive rates for all skill levels.', 'KCPS', 'belleville', 'illinois', null, 4.6, 89, 'https://example.com/midwest-flight-training', '(618) 555-0202', false, '61', '[{"name":"Gary Novak","title":"Owner / Chief Pilot","phone":"(618) 555-0202","email":"gnovak@example.com"},{"name":"Pam Weston","title":"Front Desk / Scheduling","phone":"(618) 555-0203","email":"pweston@example.com"}]'::jsonb, '6-9', '3-6'),
  ('suncoast-aviation', 'Suncoast Aviation', 'suncoast-aviation', 'Premier flight school serving the Miami–Fort Lauderdale metro from Pompano Beach Airpark. Year-round VFR flying conditions and an ATP-focused training pipeline.', 'KPMP', 'pembroke-pines', 'florida', null, 4.8, 142, 'https://example.com/suncoast-aviation', '(954) 555-0303', true, '141', '[{"name":"Carlos Vega","title":"Owner","phone":"(954) 555-0303","email":"cvega@example.com"},{"name":"Angela Marsh","title":"Chief Pilot / Director of Training","phone":"(954) 555-0304","email":"amarsh@example.com"},{"name":"Jordan Lee","title":"Front Desk / Scheduling","phone":"(954) 555-0305","email":"jlee@example.com"}]'::jsonb, '20-30', '20-30'),
  ('st-louis-flight-academy', 'St. Louis Flight Academy', 'st-louis-flight-academy', 'Located at St. Louis Lambert International, we offer professional-level training programs for aspiring pilots at every stage — from discovery flights to ATP prep.', 'KSTL', 'st-louis', 'missouri', null, 4.9, 67, 'https://example.com/st-louis-flight-academy', '(314) 555-0404', true, '141', '[{"name":"Thomas Ellery","title":"Owner / Chief Pilot","phone":"(314) 555-0404","email":"tellery@example.com"},{"name":"Rachel Burns","title":"Director of Training","phone":"(314) 555-0405","email":"rburns@example.com"},{"name":"Neil Cho","title":"Front Desk / Scheduling","phone":"(314) 555-0406","email":"ncho@example.com"}]'::jsonb, '10-20', '10-20'),
  ('heartland-flyers-kc', 'Heartland Flyers', 'heartland-flyers', 'Training Kansas City area pilots for over 20 years from Charles B. Wheeler Downtown Airport. Heartland Flyers'' downtown location is the gateway to our regional flight training network.', 'KMKC', 'kansas-city', 'missouri', 'heartland-flyers', 4.8, 142, 'https://example.com/heartland-flyers', '(816) 555-0505', true, '61', '[{"name":"Frank Briggs","title":"Owner / Founder","phone":"(816) 555-0505","email":"fbriggs@example.com"},{"name":"Donna Pierce","title":"Chief Pilot","phone":"(816) 555-0507","email":"dpierce@example.com"},{"name":"Sam Okafor","title":"Front Desk / Scheduling","phone":"(816) 555-0508","email":"sokafor@example.com"}]'::jsonb, '10-20', '10-20'),
  ('heartland-flyers-overland-park', 'Heartland Flyers – Overland Park', 'heartland-flyers-overland-park', 'Heartland Flyers'' Johnson County location at Overland Park Executive Airport serves the Kansas side of the KC metro with the same trusted instruction and fleet.', 'KOJC', 'overland-park', 'kansas', 'heartland-flyers', 4.7, 61, 'https://example.com/heartland-flyers', '(913) 555-0506', false, '61', '[{"name":"Casey Tran","title":"Location Manager / CFI","phone":"(913) 555-0506","email":"ctran@example.com"},{"name":"Bria Owens","title":"Front Desk / Scheduling","phone":"(913) 555-0509","email":"bowens@example.com"}]'::jsonb, '6-9', '6-9'),
  ('pacific-coast-flight-school', 'Pacific Coast Flight School', 'pacific-coast-flight-school', 'Based at Montgomery-Gibbs Executive Airport in San Diego, Pacific Coast offers year-round training in some of the country''s most favorable VFR flying conditions.', 'KMYF', 'san-diego', 'california', null, 4.7, 210, 'https://example.com/pacific-coast-flight-school', '(619) 555-0606', true, 'both', '[{"name":"Linda Hayashi","title":"Owner / Chief Pilot","phone":"(619) 555-0606","email":"lhayashi@example.com"},{"name":"Greg Fontaine","title":"Director of Training","phone":"(619) 555-0607","email":"gfontaine@example.com"},{"name":"Maya Torres","title":"Front Desk / Scheduling","phone":"(619) 555-0608","email":"mtorres@example.com"}]'::jsonb, '20-30', '20-30'),
  ('phoenix-flight-academy', 'Phoenix Flight Academy', 'phoenix-flight-academy', 'Accelerated pilot training programs at Deer Valley Airport — one of the nation''s busiest single-runway GA airports — in the heart of the Phoenix metro.', 'KDVT', 'phoenix', 'arizona', null, 4.7, 98, 'https://example.com/phoenix-flight-academy', '(602) 555-0707', true, '141', '[]'::jsonb, null, null),
  ('tennessee-flight-training-nashville', 'Tennessee Flight Training', 'tennessee-flight-training', 'Tennessee Flight Training''s Nashville location at BNA offers flexible scheduling and a modern fleet for students in Middle Tennessee.', 'KBNA', 'nashville', 'tennessee', 'tennessee-flight-training', 4.5, 73, 'https://example.com/tennessee-flight-training', '(615) 555-0808', false, '61', '[]'::jsonb, null, null),
  ('tennessee-flight-training-chattanooga', 'Tennessee Flight Training – Chattanooga', 'tennessee-flight-training-chattanooga', 'Tennessee Flight Training''s Chattanooga location serves East Tennessee pilots with the same quality instruction and fleet as the Nashville campus.', 'KCHA', 'chattanooga', 'tennessee', 'tennessee-flight-training', 4.4, 38, 'https://example.com/tennessee-flight-training', '(423) 555-0809', false, '61', '[]'::jsonb, null, null)
